mapper.select:
select aia.artist_identity_application_id, aia.artist_id, aia.identity_type, aia.file_type, aia.file_name, aia.file_url, aia.file_content, aia.introduction, aia.rejection_reason, aia.reviewed_by, aia.reviewed_at, aia.applied_at, aia.status, a.artist_name from artist_identity_application aia left join artist a on aia.artist_id = a.artist_id
and a.artist_name like concat('%',#{artistApplicationIdentityPageDTO.artistName},'%')
and aia.identity_type = #{artistApplicationIdentityPageDTO.identityType}
and aia.status = #{artistApplicationIdentityPageDTO.status}
